+    let mut chan = make_channel(10, false);
+    chan.set_tick(1000);
+    chan.send("late").unwrap();
+    chan.set_tick(100);
+    chan.send("early").unwrap();
+    let oldest = chan.oldest_pending().unwrap();
+    assert_eq!(oldest.created_at_tick, 100);
+}
